// winds.tw news remake — placeholder
// 目的：把 news payload 正規化後送到 Creator 入庫（SSOT）
// 注意：繁中註記，方便 Jeffery 維護

const tz = 'Asia/Taipei';
const b = $json || {};

return [{
  json: {
    source: 'winds_news',
    newsId: (b.newsId || '').toString(),
    url: (b.url || '').toString(),
    title: (b.title || '').toString(),
    contentText: (b.contentText || b.content || '').toString(),
    timezone: tz,
    tone: 'warm_clear',
    cta: 'line_free_divination',
    channels: ['ig','threads','fb','linkedin']
  }
}];
